import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
// import { useNavigate } from 'react-router-dom';
// import StatsSection from '../components/StatsSection';
// import NewsSection from '../components/NewsSection';
import '../styles/CoursesPage.css';

const CoursesPage = () => {
    const { t } = useTranslation();
    // const navigate = useNavigate();
    const [isVisible, setIsVisible] = useState(false);
    const [selectedCourse, setSelectedCourse] = useState(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [activeFilter, setActiveFilter] = useState('all');
    const sectionRef = useRef(null);

    // Enhanced course data with more courses
    const courses = [
        {
            id: 1,
            title: "Full Stack Web Development",
            category: "web-development",
            level: "Beginner to Advanced",
            duration: "12 weeks",
            price: "¥35,000",
            rating: 4.9,
            students: 1250,
            image: require('../assets/images/png5.jpg'),
            instructor: "John Smith",
            description: "Master modern web development with React, Node.js, and MongoDB",
            fullDescription: "This comprehensive course covers everything from HTML/CSS basics to advanced React patterns, backend development with Node.js and Express, database design with MongoDB, and deployment strategies.",
            skills: ["React", "Node.js", "MongoDB", "Express", "JavaScript", "HTML/CSS"],
            curriculum: [
                "Frontend Fundamentals (HTML, CSS, JavaScript)",
                "React Development & State Management",
                "Backend Development with Node.js",
                "Database Design & MongoDB",
                "API Development & Integration",
                "Deployment & DevOps"
            ],
            prerequisites: ["Basic computer skills", "Problem-solving mindset"],
            certificate: true,
            support: "24/7 Community Support"
        },
        {
            id: 2,
            title: "Data Science & Analytics",
            category: "data-science",
            level: "Intermediate",
            duration: "16 weeks",
            price: "¥48,000",
            rating: 4.8,
            students: 980,
            image: require('../assets/images/png5.jpg'),
            instructor: "Dr. Sarah Johnson",
            description: "Learn Python, machine learning, and data visualization techniques",
            fullDescription: "Dive deep into data science with Python, statistical analysis, machine learning algorithms, and data visualization. Work with real datasets and build predictive models.",
            skills: ["Python", "Pandas", "NumPy", "Scikit-learn", "Matplotlib", "Seaborn"],
            curriculum: [
                "Python for Data Science",
                "Statistical Analysis & Probability",
                "Data Cleaning & Preprocessing",
                "Machine Learning Algorithms",
                "Data Visualization",
                "Capstone Project"
            ],
            prerequisites: ["Basic programming knowledge", "Mathematics background"],
            certificate: true,
            support: "Mentor-guided learning"
        },
        {
            id: 3,
            title: "Cybersecurity Fundamentals",
            category: "cybersecurity",
            level: "Beginner",
            duration: "10 weeks",
            price: "¥30,000",
            rating: 4.7,
            students: 750,
            image: require('../assets/images/png5.jpg'),
            instructor: "Michael Chen",
            description: "Protect digital assets and learn ethical hacking techniques",
            fullDescription: "Master cybersecurity fundamentals including network security, ethical hacking, risk assessment, and security frameworks. Hands-on labs with real-world scenarios.",
            skills: ["Network Security", "Ethical Hacking", "Risk Assessment", "Security Frameworks"],
            curriculum: [
                "Introduction to Cybersecurity",
                "Network Security Fundamentals",
                "Ethical Hacking & Penetration Testing",
                "Risk Management",
                "Security Compliance",
                "Incident Response"
            ],
            prerequisites: ["Basic networking knowledge"],
            certificate: true,
            support: "Industry expert mentorship"
        },
        {
            id: 4,
            title: "Cloud Computing with AWS",
            category: "cloud-computing",
            level: "Intermediate",
            duration: "14 weeks",
            price: "¥42,000",
            rating: 4.8,
            students: 890,
            image: require('../assets/images/png5.jpg'),
            instructor: "Alex Rodriguez",
            description: "Master AWS cloud services and modern cloud architecture",
            fullDescription: "Learn to design, deploy, and manage scalable applications on AWS. Cover EC2, S3, Lambda, RDS, and more. Prepare for AWS certification while building real-world projects.",
            skills: ["AWS", "EC2", "S3", "Lambda", "CloudFormation", "DevOps"],
            curriculum: [
                "AWS Fundamentals & Setup",
                "Compute Services (EC2, Lambda)",
                "Storage Solutions (S3, EBS)",
                "Database Services (RDS, DynamoDB)",
                "Networking & Security",
                "Deployment & Monitoring"
            ],
            prerequisites: ["Basic programming", "Understanding of web applications"],
            certificate: true,
            support: "AWS certified instructors"
        },
        {
            id: 5,
            title: "AI & Machine Learning",
            category: "ai-ml",
            level: "Advanced",
            duration: "20 weeks",
            price: "¥65,000",
            rating: 4.9,
            students: 650,
            image: require('../assets/images/png5.jpg'),
            instructor: "Dr. Emily Watson",
            description: "Deep dive into artificial intelligence and machine learning algorithms",
            fullDescription: "Comprehensive AI/ML course covering neural networks, deep learning, computer vision, and natural language processing. Build real AI applications.",
            skills: ["TensorFlow", "PyTorch", "Computer Vision", "NLP", "Deep Learning", "Neural Networks"],
            curriculum: [
                "Machine Learning Fundamentals",
                "Neural Networks & Deep Learning",
                "Computer Vision with CNNs",
                "Natural Language Processing",
                "Reinforcement Learning",
                "AI Ethics & Deployment"
            ],
            prerequisites: ["Strong programming skills", "Advanced mathematics", "Statistics background"],
            certificate: true,
            support: "Research-level mentorship"
        },
        {
            id: 6,
            title: "Mobile App Development",
            category: "mobile-development",
            level: "Intermediate",
            duration: "12 weeks",
            price: "¥38,000",
            rating: 4.6,
            students: 920,
            image: require('../assets/images/png5.jpg'),
            instructor: "James Park",
            description: "Build native iOS and Android apps with React Native",
            fullDescription: "Learn to develop cross-platform mobile applications using React Native. Cover navigation, state management, API integration, and deployment to app stores.",
            skills: ["React Native", "JavaScript", "Mobile UI/UX", "API Integration", "App Store Deployment"],
            curriculum: [
                "React Native Fundamentals",
                "Navigation & Routing",
                "State Management",
                "Native Modules & APIs",
                "Testing & Debugging",
                "App Store Deployment"
            ],
            prerequisites: ["JavaScript knowledge", "React experience preferred"],
            certificate: true,
            support: "Mobile development experts"
        }
    ];

    const filteredCourses = activeFilter === 'all' 
        ? courses 
        : courses.filter(course => course.category === activeFilter);

    useEffect(() => {
        setIsVisible(true);

        const createCubes = () => {
            const world = document.querySelector('.world');
            if (!world) return;

            for (let i = 0; i < 15; i++) {
                const cube = document.createElement('div');
                cube.className = 'cube';

                const x = (Math.random() - 0.5) * 1000;
                const y = (Math.random() - 0.5) * 1000;
                const z = (Math.random() - 0.5) * 1000;
                const size = Math.random() * 50 + 20;

                cube.style.width = `${size}px`;
                cube.style.height = `${size}px`;
                cube.style.transform = `translate3d(${x}px, ${y}px, ${z}px)`;

                ['front', 'back', 'right', 'left', 'top', 'bottom'].forEach(face => {
                    const el = document.createElement('div');
                    el.className = `cube-face ${face}`;
                    cube.appendChild(el);
                });

                world.appendChild(cube);
            }
        };

        createCubes();

        return () => {
            const world = document.querySelector('.world');
            if (world) {
                while (world.firstChild) {
                    world.removeChild(world.firstChild);
                }
            }
        };
    }, []);

    const openModal = (course) => {
        setSelectedCourse(course);
        setIsModalOpen(true);
        document.body.style.overflow = 'hidden';
    };

    const closeModal = () => {
        setIsModalOpen(false);
        setSelectedCourse(null);
        document.body.style.overflow = 'unset';
    };

    const handleEnrollment = () => {
        // Navigate to application form with course data
        navigate('/apply', { 
            state: { 
                courseId: selectedCourse.id,
                courseName: selectedCourse.title,
                coursePrice: selectedCourse.price,
                courseDuration: selectedCourse.duration
            } 
        });
        closeModal();
    };

    // Close modal when clicking outside
    const handleModalClick = (e) => {
        if (e.target === e.currentTarget) {
            closeModal();
        }
    };

    return (
        <div className="courses-page">
            {/* Hero Section */}
            <section ref={sectionRef} className={`courses-hero ${isVisible ? 'visible' : ''}`}>
                <div className="scene">
                    <div className="world">
                        <div className="floor"></div>
                    </div>
                    <div className="glow glow-1"></div>
                    <div className="glow glow-2"></div>
                </div>

                <div className="container">
                    <div className="hero-content">
                        <div className="hero-text">
                            <div className="hero-badge">
                                <span className="badge-icon material-icons">school</span>
                                {t('courses.hero.badge')}
                            </div>
                            <h1 className="hero-title">{t('courses.hero.title')} <span className="highlight-text">{t('courses.hero.highlight')}</span></h1>
                            <p className="hero-description">{t('courses.hero.description')}</p>

                            <div className="hero-cta-group">
                                <button className="btn btn-primary">
                                    <span className="material-icons">search</span>
                                    {t('courses.hero.findCourse')}
                                </button>
                                <button className="btn btn-outline">
                                    <span className="material-icons">info</span>
                                    {t('courses.hero.programGuide')}
                                </button>
                            </div>

                            <div className="hero-stats">
                                <div className="stat-item">
                                    <div className="stat-number">30+</div>
                                    <div className="stat-label">{t('courses.stats.courses')}</div>
                                </div>
                                <div className="stat-item">
                                    <div className="stat-number">95%</div>
                                    <div className="stat-label">{t('courses.stats.jobPlacement')}</div>
                                </div>
                                <div className="stat-item">
                                    <div className="stat-number">4.9</div>
                                    <div className="stat-label">{t('courses.stats.studentRating')}</div>
                                </div>
                            </div>
                        </div>

                        <div className="hero-image-wrapper">
                            <div className="image-card">
                                <img 
                                    src={require('../assets/images/png5.jpg')} 
                                    alt={t('courses.hero.imageAlt')} 
                                    className="hero-image" 
                                />
                                <div className="image-overlay"></div>
                                <div className="tech-tag-group">
                                    <div className="tech-tag">{t('courses.webDevelopment')}</div>
                                    <div className="tech-tag">{t('courses.dataScience')}</div>
                                    <div className="tech-tag">{t('courses.cybersecurity')}</div>
                                    <div className="tech-tag">{t('courses.cloudComputing')}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            {/* Course Filters */}
            <div id="courses" className="course-filters-container">
                <div className="container">
                    <div className="flex flex-wrap justify-center gap-4 mb-12">
                        <button 
                            onClick={() => setActiveFilter('all')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'all' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">school</span>
                            All Categories
                        </button>
                        <button 
                            onClick={() => setActiveFilter('web-development')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'web-development' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">code</span>
                            Web Development
                        </button>
                        <button 
                            onClick={() => setActiveFilter('data-science')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'data-science' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">analytics</span>
                            Data Science
                        </button>
                        <button 
                            onClick={() => setActiveFilter('cybersecurity')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'cybersecurity' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">security</span>
                            Cybersecurity
                        </button>
                        <button 
                            onClick={() => setActiveFilter('cloud-computing')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'cloud-computing' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">cloud</span>
                            Cloud Computing
                        </button>
                        <button 
                            onClick={() => setActiveFilter('ai-ml')}
                            className={`px-6 py-3 rounded-full font-medium transition-all duration-300 flex items-center gap-2 ${
                                activeFilter === 'ai-ml' 
                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg' 
                                    : 'bg-white text-gray-700 hover:bg-gray-50 border border-gray-200'
                            }`}
                        >
                            <span className="material-icons text-sm">smart_toy</span>
                            AI & ML
                        </button>
                    </div>
                </div>
            </div>

            {/* Courses Grid */}
            <section className="py-20 bg-gray-50">
                <div className="container mx-auto px-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {filteredCourses.map((course) => (
                            <div 
                                key={course.id} 
                                className="bg-white rounded-2xl shadow-lg hover:shadow-2xl transition-all duration-500 transform hover:-translate-y-2 group overflow-hidden"
                            >
                                <div className="relative overflow-hidden">
                                    <img 
                                        src={course.image} 
                                        alt={course.title}
                                        className="w-full h-48 object-cover group-hover:scale-110 transition-transform duration-500"
                                    />
                                    <div className="absolute top-4 right-4 bg-white bg-opacity-90 px-3 py-1 rounded-full text-sm font-bold text-gray-800">
                                        {course.price}
                                    </div>
                                    <div className="absolute top-4 left-4 bg-gradient-to-r from-blue-500 to-purple-600 text-white px-3 py-1 rounded-full text-sm font-medium">
                                        {course.level}
                                    </div>
                                </div>

                                <div className="p-6">
                                    <div className="flex items-center justify-between mb-2">
                                        <span className="text-sm text-gray-500 capitalize">
                                            {course.category.replace('-', ' ')}
                                        </span>
                                        <div className="flex items-center gap-1">
                                            <span className="material-icons text-yellow-400 text-sm">star</span>
                                            <span className="text-sm font-medium">{course.rating}</span>
                                        </div>
                                    </div>

                                    <h3 className="text-xl font-bold text-gray-900 mb-3 group-hover:text-blue-600 transition-colors">
                                        {course.title}
                                    </h3>

                                    <p className="text-gray-600 mb-4 text-sm leading-relaxed">
                                        {course.description}
                                    </p>

                                    <div className="flex items-center justify-between mb-4">
                                        <div className="flex items-center gap-2 text-sm text-gray-500">
                                            <span className="material-icons text-sm">schedule</span>
                                            {course.duration}
                                        </div>
                                        <div className="flex items-center gap-2 text-sm text-gray-500">
                                            <span className="material-icons text-sm">people</span>
                                            {course.students} students
                                        </div>
                                    </div>

                                    <div className="flex gap-3">
                                        <button 
                                            onClick={() => openModal(course)}
                                            className="flex-1 bg-gradient-to-r from-blue-500 to-purple-600 text-white py-3 px-4 rounded-xl font-medium hover:from-blue-600 hover:to-purple-700 transition-all duration-300 flex items-center justify-center gap-2"
                                        >
                                            <span className="material-icons text-sm">info</span>
                                            Learn More
                                        </button>
                                        <button className="px-4 py-3 border-2 border-gray-200 rounded-xl hover:border-blue-500 hover:text-blue-500 transition-all duration-300">
                                            <span className="material-icons">favorite_border</span>
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Course Modal - Centered and smaller */}
            {isModalOpen && selectedCourse && (
                <div 
                    className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center p-4"
                    style={{ zIndex: 10000 }}
                    onClick={handleModalClick}
                >
                    <div 
                        className="bg-white rounded-xl max-w-lg w-full max-h-[75vh] overflow-y-auto transform transition-all duration-300 shadow-2xl"
                        onClick={(e) => e.stopPropagation()}
                    >
                        {/* Modal Header */}
                        <div className="relative">
                            <img 
                                src={selectedCourse.image} 
                                alt={selectedCourse.title}
                                className="w-full h-40 object-cover rounded-t-xl"
                            />
                            <button 
                                onClick={closeModal}
                                className="absolute top-2 right-2 bg-white bg-opacity-90 hover:bg-opacity-100 rounded-full p-2 transition-all duration-300 shadow-lg"
                            >
                                <span className="material-icons text-gray-700 text-sm">close</span>
                            </button>
                            <div className="absolute bottom-2 left-3 bg-white bg-opacity-95 px-3 py-1 rounded-full shadow-lg">
                                <span className="text-lg font-bold text-gray-900">{selectedCourse.price}</span>
                            </div>
                        </div>

                        <div className="p-5">
                            {/* Course Title & Basic Info */}
                            <div className="mb-4">
                                <div className="flex items-center gap-2 mb-2">
                                    <span className="bg-gradient-to-r from-blue-500 to-purple-600 text-white px-2 py-1 rounded-full text-xs font-medium">
                                        {selectedCourse.level}
                                    </span>
                                    <div className="flex items-center gap-1">
                                        <span className="material-icons text-yellow-400 text-sm">star</span>
                                        <span className="font-medium text-sm">{selectedCourse.rating}</span>
                                        <span className="text-gray-500 text-xs">({selectedCourse.students} students)</span>
                                    </div>
                                </div>

                                <h2 className="text-xl font-bold text-gray-900 mb-2">{selectedCourse.title}</h2>
                                <p className="text-gray-600 text-sm">{selectedCourse.fullDescription}</p>
                            </div>

                            {/* Course Details */}
                            <div className="mb-4">
                                <h3 className="text-md font-bold text-gray-900 mb-2">Course Details</h3>
                                <div className="grid grid-cols-1 gap-2 text-xs">
                                    <div className="flex items-center gap-2">
                                        <span className="material-icons text-blue-500 text-sm">schedule</span>
                                        <span>Duration: {selectedCourse.duration}</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="material-icons text-blue-500 text-sm">person</span>
                                        <span>Instructor: {selectedCourse.instructor}</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="material-icons text-blue-500 text-sm">support</span>
                                        <span>{selectedCourse.support}</span>
                                    </div>
                                    {selectedCourse.certificate && (
                                        <div className="flex items-center gap-2">
                                            <span className="material-icons text-blue-500 text-sm">workspace_premium</span>
                                            <span>Certificate of Completion</span>
                                        </div>
                                    )}
                                </div>
                            </div>

                            {/* Skills */}
                            <div className="mb-4">
                                <h3 className="text-md font-bold text-gray-900 mb-2">Skills You'll Learn</h3>
                                <div className="flex flex-wrap gap-1">
                                    {selectedCourse.skills.slice(0, 4).map((skill, index) => (
                                        <span 
                                            key={index}
                                            className="bg-blue-100 text-blue-800 px-2 py-1 rounded-full text-xs"
                                        >
                                            {skill}
                                        </span>
                                    ))}
                                </div>
                            </div>

                            {/* Curriculum */}
                            <div className="mb-5">
                                <h3 className="text-md font-bold text-gray-900 mb-2">What You'll Learn</h3>
                                <div className="space-y-1">
                                    {selectedCourse.curriculum.slice(0, 3).map((item, index) => (
                                        <div key={index} className="flex items-start gap-2">
                                            <span className="material-icons text-green-500 text-sm mt-0.5">check_circle</span>
                                            <span className="text-xs text-gray-700">{item}</span>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            {/* Action Buttons */}
                            <div className="flex gap-2">
                                <button 
                                    onClick={handleEnrollment}
                                    className="flex-1 bg-gradient-to-r from-blue-500 to-purple-600 text-white py-2 px-3 rounded-lg font-medium hover:from-blue-600 hover:to-purple-700 transition-all duration-300 flex items-center justify-center gap-2 text-sm"
                                >
                                    <span className="material-icons text-sm">play_circle</span>
                                    Enroll Now
                                </button>
                                <button className="px-3 py-2 border-2 border-gray-200 rounded-lg hover:border-blue-500 hover:text-blue-500 transition-all duration-300">
                                    <span className="material-icons text-sm">bookmark_border</span>
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Keep existing sections
            <section className="stats-section">
                <div className="container">
                    <StatsSection />
                </div>
            </section>

            <section className="news-section">
                <div className="container">
                    <div className="section-header">
                        <h2>{t('courses.news.title')}</h2>
                        <p>{t('courses.news.description')}</p>
                    </div>
                    <NewsSection />
                </div>
            </section> */}
        </div>
    );
};

export default CoursesPage;
